def solution(n: int = 100) -> int:
    """
    Calculates partition count p(n) using the Pentagonal Number Theorem.
    p(n) = sum_{k != 0} (-1)^(k-1) * p(n - k(3k-1)/2)
    """
    partitions = [0] * (n + 1)
    partitions[0] = 1

    for i in range(1, n + 1):
        k = 1
        while True:
            # Generalized pentagonal numbers: k(3k-1)/2 for k = 1, -1, 2, -2, ...
            for sign in [1, -1]:
                gk = sign * k * (3 * sign * k - 1) // 2
                if gk > i: break

                # Pentagonal number theorem recurrence
                if k % 2 == 1:
                    partitions[i] += partitions[i - gk]
                else:
                    partitions[i] -= partitions[i - gk]
            else:
                # Only break if both signs exceeded i
                if gk > i: 
                    k += 1
                    continue
            break

    return partitions[n] - 1


